const { expect } = require('chai');
const Qualifier = require('../../../../../src/lib/annotations/inject/Qualifier');
const QualifierProcessor = require('../../../../../src/lib/processors/inject/QualifierProcessor'); // Singleton

describe('@Qualifier Processor', () => {
  let ctx;
  let consumerInstance;
  let registered;

  beforeEach(() => {
    consumerInstance = {};
    registered = new Map();

    // Mock DI container
    ctx = {
      container: {
        // Stellt bereits existierende Beans bereit
        resolveByQualifier(name) {
          return registered.get(name);
        }
      },
      log: [],
    };
  });

  it('should inject qualified dependency from DI container', () => {
    class MyService {}
    const serviceInstance = new MyService();

    // Bean bereits im DI-Container registrieren
    registered.set('MyService', serviceInstance);

    const meta = {
      annotation: Qualifier,
      className: 'Consumer',
      classRef: class {},
      propertyName: 'myService',
      args: ['MyService'],
      instance: consumerInstance
    };

    QualifierProcessor.processDI(meta, ctx);

    // Property wurde injiziert
    expect(consumerInstance.myService).to.equal(serviceInstance);

    // Log überprüfung
    expect(ctx.log).to.include('@Qualifier injected: myService ← MyService');
  });

  it('should log a warning if qualifier cannot be resolved', () => {
    const meta = {
      annotation: Qualifier,
      className: 'Consumer',
      classRef: class {},
      propertyName: 'unknownService',
      args: ['UnknownService'],
      instance: consumerInstance
    };

    QualifierProcessor.processDI(meta, ctx);

    expect(consumerInstance.unknownService).to.be.undefined;
    expect(ctx.log).to.include(
      "@Qualifier could not resolve dependency for 'UnknownService'"
    );
  });

  it('should log a warning if no qualifier name is provided', () => {
    const meta = {
      annotation: Qualifier,
      className: 'Consumer',
      classRef: class {},
      propertyName: 'myService',
      args: [],
      instance: consumerInstance
    };

    QualifierProcessor.processDI(meta, ctx);

    expect(ctx.log.some(msg => msg.includes('requires a name argument'))).to.be.true;
  });
});
